code = """import json
import os

key_results = 'var_function-call-853745788429203349'
results = locals()[key_results]

with open('state.json', 'r') as f:
    state = json.load(f)

for row in results:
    if 'Symbol' in row:
        state['found_symbols'].append(row['Symbol'])

state['current_index'] += state['batch_size']
with open('state.json', 'w') as f:
    json.dump(state, f)

# Generate next 5 batches (to test multiple calls)
start_idx = state['current_index']
batch_size = state['batch_size']
valid_symbols = state['valid_symbols']

tool_calls = []
sq = chr(39)
dq = chr(34)

# We will generate up to 5 batches
for k in range(5):
    idx = start_idx + k * batch_size
    if idx >= len(valid_symbols):
        break
    
    chunk = valid_symbols[idx : idx + batch_size]
    sub_queries = []
    for sym in chunk:
        q = "(SELECT " + sq + sym + sq + " as Symbol FROM " + dq + sym + dq + " WHERE " + dq + "Adj Close" + dq + " > 200 AND Date >= " + sq + "2015-01-01" + sq + " AND Date <= " + sq + "2015-12-31" + sq + " LIMIT 1)"
        sub_queries.append(q)
    
    full_query = " UNION ALL ".join(sub_queries)
    
    tool_call = {
        "tool": "query_db",
        "args": {
            "db_name": "stocktrade_database",
            "query": full_query
        }
    }
    tool_calls.append(tool_call)

print('__RESULT__:')
print(json.dumps(tool_calls))"""

